mapper.select:
SELECT * FROM (
    SELECT T.*, ROWNUM RN FROM (
        SELECT id, username, display_name, email, phone, status, mfa_enabled, created_at
        FROM users

            is_deleted = 0

                AND (username LIKE '%' || #{keyword} || '%'
                     OR display_name LIKE '%' || #{keyword} || '%')


                AND status = #{status}


        ORDER BY created_at DESC
    ) T WHERE ROWNUM <= #{offset} + #{size}
) WHERE RN > #{offset}

mapper.update:
UPDATE users
display_name = #{displayName}, email = #{email}, phone = #{phone}, password_hash = #{passwordHash}, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE users
SET is_deleted = 1, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE users
SET status = #{status}, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}
